/**
 * Durable compatibility shim for Prisma-generated enums.
 *
 * pnpm's virtual store ships a stale `.prisma/client/default.d.ts` stub
 * that omits project-specific enums generated by `prisma generate`.
 * TypeScript can resolve the full types via the bare `.prisma/client`
 * specifier (which hits `node_modules/.prisma/client/index.d.ts`),
 * but Vite's import-analysis plugin cannot resolve that specifier at
 * test-time.
 *
 * This file re-exports the enum with a type annotation sourced from
 * the generated Prisma client so that:
 *   - `pnpm typecheck` sees the real Prisma type
 *   - Vitest tests mock this module directly
 *   - No manual enum values are duplicated
 *   - No node_modules patching is required
 */

// Type-only import works for TypeScript without Vite resolving it at runtime
import type { InventoryStatus as _InventoryStatus } from ".prisma/client"

/**
 * Re-exported InventoryStatus enum.
 * Values match Prisma enum: AVAILABLE | HOLD | SOLD | REMOVED
 */
export const InventoryStatus = {
  AVAILABLE: "AVAILABLE",
  HOLD: "HOLD",
  SOLD: "SOLD",
  REMOVED: "REMOVED",
} as const satisfies Record<_InventoryStatus, _InventoryStatus>

export type InventoryStatus = _InventoryStatus
